package com.example.enterpriseapp.service;

import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.repository.AppUserRepository;
import java.util.List;
import java.util.Optional;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class UserService {

    private final AppUserRepository appUserRepository;

    public UserService(AppUserRepository appUserRepository) {
        this.appUserRepository = appUserRepository;
    }

    public AppUser createUser(AppUser user) {
        if (appUserRepository.existsByUsername(user.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (appUserRepository.existsByEmail(user.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }
        return appUserRepository.save(user);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> getUserById(Long id) {
        return appUserRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> getUserByUsername(String username) {
        return appUserRepository.findByUsername(username);
    }

    @Transactional(readOnly = true)
    public List<AppUser> getAllUsers() {
        return appUserRepository.findAll();
    }

    public AppUser updateUser(Long id, AppUser updatedUser) {
        AppUser existing = appUserRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        existing.setUsername(updatedUser.getUsername());
        existing.setEmail(updatedUser.getEmail());
        existing.setPasswordHash(updatedUser.getPasswordHash());
        existing.setEnabled(updatedUser.isEnabled());
        return appUserRepository.save(existing);
    }

    public void deleteUser(Long id) {
        if (!appUserRepository.existsById(id)) {
            throw new IllegalArgumentException("User not found");
        }
        appUserRepository.deleteById(id);
    }
}

package com.example.enterpriseapp.service;

import com.example.enterpriseapp.domain.AccountTransaction;
import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.repository.AccountTransactionRepository;
import com.example.enterpriseapp.repository.AppUserRepository;
import java.math.BigDecimal;
import java.util.List;
import java.util.Optional;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class TransactionService {

    private final AccountTransactionRepository transactionRepository;
    private final AppUserRepository userRepository;

    public TransactionService(AccountTransactionRepository transactionRepository, AppUserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    public AccountTransaction createTransaction(Long userId, BigDecimal amount, String currency, String status) {
        AppUser user = userRepository.findById(userId)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        AccountTransaction tx = new AccountTransaction();
        tx.setTransactionRef(UUID.randomUUID().toString());
        tx.setUser(user);
        tx.setAmount(amount);
        tx.setCurrency(currency);
        tx.setStatus(status);
        return transactionRepository.save(tx);
    }

    @Transactional(readOnly = true)
    public Optional<AccountTransaction> getTransactionById(Long id) {
        return transactionRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public Optional<AccountTransaction> getTransactionByRef(String ref) {
        return transactionRepository.findByTransactionRef(ref);
    }

    @Transactional(readOnly = true)
    public List<AccountTransaction> getTransactionsByUser(Long userId) {
        return transactionRepository.findByUserId(userId);
    }

    @Transactional(readOnly = true)
    public List<AccountTransaction> getTransactionsByStatus(String status) {
        return transactionRepository.findByStatus(status);
    }

    public AccountTransaction updateTransactionStatus(Long id, String status) {
        AccountTransaction tx = transactionRepository.findById(id)
                .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        tx.setStatus(status);
        return transactionRepository.save(tx);
    }

    public void deleteTransaction(Long id) {
        if (!transactionRepository.existsById(id)) {
            throw new IllegalArgumentException("Transaction not found");
        }
        transactionRepository.deleteById(id);
    }
}

package com.example.enterpriseapp.web;

import com.example.enterpriseapp.domain.AppUser;
import com.example.enterpriseapp.service.UserService;
import java.util.List;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    public ResponseEntity<AppUser> createUser(@RequestBody AppUser user) {
        return ResponseEntity.status(HttpStatus.CREATED).body(userService.createUser(user));
    }

    @GetMapping("/{id}")
    public ResponseEntity<AppUser> getUser(@PathVariable Long id) {
        return userService.getUserById(id)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    @GetMapping
    public ResponseEntity<List<AppUser>> getAllUsers() {
        return ResponseEntity.ok(userService.getAllUsers());
    }

    @PutMapping("/{id}")
    public ResponseEntity<AppUser> updateUser(@PathVariable Long id, @RequestBody AppUser user) {
        return ResponseEntity.ok(userService.updateUser(id, user));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteUser(@PathVariable Long id) {
        userService.deleteUser(id);
        return ResponseEntity.noContent().build();
    }
}

package com.example.enterpriseapp.web;

import com.example.enterpriseapp.domain.AccountTransaction;
import com.example.enterpriseapp.service.TransactionService;
import java.math.BigDecimal;
import java.util.List;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {

    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    @PostMapping("/user/{userId}")
    public ResponseEntity<AccountTransaction> createTransaction(
            @PathVariable Long userId,
            @RequestParam BigDecimal amount,
            @RequestParam String currency,
            @RequestParam String status) {
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(transactionService.createTransaction(userId, amount, currency, status));
    }

    @GetMapping("/{id}")
    public ResponseEntity<AccountTransaction> getTransaction(@PathVariable Long id) {
        return transactionService.getTransactionById(id)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    @GetMapping("/user/{userId}")
    public ResponseEntity<List<AccountTransaction>> getTransactionsByUser(@PathVariable Long userId) {
        return ResponseEntity.ok(transactionService.getTransactionsByUser(userId));
    }

    @GetMapping
    public ResponseEntity<List<AccountTransaction>> getTransactionsByStatus(@RequestParam String status) {
        return ResponseEntity.ok(transactionService.getTransactionsByStatus(status));
    }

    @PutMapping("/{id}/status")
    public ResponseEntity<AccountTransaction> updateStatus(@PathVariable Long id, @RequestParam String status) {
        return ResponseEntity.ok(transactionService.updateTransactionStatus(id, status));
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteTransaction(@PathVariable Long id) {
        transactionService.deleteTransaction(id);
        return ResponseEntity.noContent().build();
    }
}

